<script setup>
import { computed, reactive, ref, watch } from 'vue'
import { Delete, Edit, Plus, Star, View } from '@element-plus/icons-vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import RestorationModelViewer from './RestorationModelViewer.vue'
import { getRestorationVersion } from '@/api/conservationRestoration'
const props=defineProps({result:{type:Object,required:true},context:{type:Object,required:true},readOnly:Boolean})
const emit=defineEmits(['dirty','navigate','upload-media','upload-model','delete-media','delete-model','restore-version'])
const tab=ref('overview'), selectedPartId=ref(null), partDialog=ref(false), sourceDialog=ref(false)
const mediaInput=ref(null),modelInput=ref(null)
const modelViewerVisible=ref(false),activeModel=ref(null),snapshotDialog=ref(false),compareDialog=ref(false)
const snapshotVersion=ref(null),compareSelection=ref([]),compareVersions=ref([])
const editId=reactive({part:null,source:null})
const typeMap={physical:'实体复原',digital_2d:'二维数字复原',digital_3d:'三维数字复原',hybrid:'实体与数字结合',conceptual:'学术推测复原'}
const categoryMap={structure:'结构复原',shape:'形态复原',assembly:'装配复原',missing_part:'缺失部分复原',pattern:'纹饰复原',color:'色彩复原',scene:'场景复原',other:'其他'}
const confidenceMap={high:'高',medium:'中',low:'低',undetermined:'未确定'}
const partMap={original:['原始保存','original'],repaired:['原件修复','repaired'],physical_completion:['实体补配','completion'],evidence_based:['证据复原','evidence'],inferred:['推测复原','inferred'],uncertain:['无法确定','uncertain']}
const sourceMap={original_fragment:'原始残片',archaeological_context:'出土位置',symmetry:'对称关系',structural_relation:'结构连接',measurement:'尺寸测绘',detection:'检测分析',process_step:'修复过程',comparison:'前后对比',similar_artifact:'同类文物',literature:'研究文献',expert_opinion:'专家意见',digital_analysis:'数字分析',other:'其他'}
const stageMap={before:'复原前',during:'复原中',after:'复原后',final:'最终成果',evidence:'证据图',diagram:'说明图',render:'渲染图',annotation:'标注图'}
const selectedPart=computed(()=>props.result.parts.find(x=>x.id===selectedPartId.value)||props.result.parts[0])
const primary=computed(()=>props.result.media.find(x=>x.isPrimary)||props.result.media[0])
const score=computed(()=>{const e=props.result.evaluation,a=[e.evidenceScore,e.structuralScore,e.authenticityScore,e.informationScore,e.distinguishabilityScore,e.reversibilityScore,e.displayScore,e.uncertaintyScore].map(Number).filter(Boolean);return a.length?+(a.reduce((x,y)=>x+y,0)/a.length).toFixed(2):0})
const partForm=reactive({partCode:'',partName:'',partType:'original',targetLocation:'',scopeDescription:'',materialName:'',technique:'',evidenceLevel:'A',confidenceLevel:'high',removable:false,reversible:false,reversibleDescription:'',distinguishable:true,displayStyle:'',annotationText:'',percentageValue:0,modelLayer:false,modelObjectName:'',layerVisible:true,annotationPosition:{}})
const sourceForm=reactive({restorationPartId:null,sourceType:'process_step',sourceTitle:'',businessType:'process_step',businessId:null,supportDescription:'',reliability:'medium',evidenceLevel:'B',fileName:'',fileUrl:''})
const dirty=()=>{props.result.overallScore=score.value;emit('dirty')}
const openPart=x=>{editId.part=x?.id||null;Object.assign(partForm,x||{partCode:`PART-${props.result.parts.length+1}`,partName:'',partType:'original',targetLocation:'',scopeDescription:'',materialName:'',technique:'',evidenceLevel:'A',confidenceLevel:'high',removable:false,reversible:false,reversibleDescription:'',distinguishable:true,displayStyle:'',annotationText:'',percentageValue:0,modelLayer:false,modelObjectName:'',layerVisible:true,annotationPosition:{}});partDialog.value=true}
const savePart=()=>{if(!partForm.partName)return;const old=props.result.parts.find(x=>x.id===editId.part);old?Object.assign(old,partForm):props.result.parts.push({id:Date.now(),...partForm});partDialog.value=false;dirty()}
const removePart=async x=>{if(props.result.sources.some(s=>s.restorationPartId===x.id))return ElMessage.warning('请先解除该部分的依据关联');try{await ElMessageBox.confirm(`删除“${x.partName}”？`,'确认',{type:'warning'});props.result.parts.splice(props.result.parts.indexOf(x),1);dirty()}catch{}}
const openSource=x=>{editId.source=x?.id||null;Object.assign(sourceForm,x||{restorationPartId:selectedPart.value?.id||null,sourceType:'process_step',sourceTitle:'',businessType:'process_step',businessId:null,supportDescription:'',reliability:'medium',evidenceLevel:'B',fileName:'',fileUrl:''});sourceDialog.value=true}
const saveSource=()=>{if(!sourceForm.sourceTitle)return;const old=props.result.sources.find(x=>x.id===editId.source);old?Object.assign(old,sourceForm):props.result.sources.push({id:Date.now(),...sourceForm});sourceDialog.value=false;dirty()}
const addMedia=()=>mediaInput.value?.click()
const addModel=()=>modelInput.value?.click()
const onMediaFile=event=>{const file=event.target.files?.[0];if(file)emit('upload-media',file);event.target.value=''}
const onModelFile=event=>{const file=event.target.files?.[0];if(file)emit('upload-model',file);event.target.value=''}
const viewModel=model=>{activeModel.value=model;modelViewerVisible.value=true}
const addParameter=async()=>{try{const name=await ElMessageBox.prompt('请输入方法或参数名称','新增参数',{inputPlaceholder:'例如：接缝宽度'});const value=await ElMessageBox.prompt('请输入参数值','填写参数值',{inputPlaceholder:'例如：0.8 mm'});props.result.methodParameters.push({id:Date.now(),name:name.value,value:value.value,unit:'',description:''});dirty()}catch{}}
const newVersion=copy=>{const c=props.result.versions.find(x=>x.isCurrent);props.result.versions.forEach(x=>x.isCurrent=false);const versionNo=`V1.${props.result.versions.length+1}`;props.result.versions.push({id:Date.now(),versionNo,versionName:copy?`${c?.versionName||'当前版本'}副本`:'新修订版本',versionType:copy?'alternative':'revision',changeDescription:copy?'复制当前数据形成新版本':'记录本次复原成果修改',evidenceLevel:props.result.evidenceLevel,confidenceLevel:props.result.confidenceLevel,isCurrent:true,isRecommended:false,creator:props.result.principal,createTime:new Date().toLocaleString('zh-CN',{hour12:false})});props.result.currentVersion=versionNo;dirty()}
const loadVersion=async version=>{const response=await getRestorationVersion(props.result.id,version.id);return response.data}
const viewSnapshot=async version=>{try{snapshotVersion.value=await loadVersion(version);snapshotDialog.value=true}catch(e){ElMessage.error(e.message||'历史快照读取失败')}}
const onVersionSelection=rows=>{compareSelection.value=rows}
const compareSelected=async()=>{if(compareSelection.value.length!==2)return ElMessage.warning('请选择两个版本进行比较');try{compareVersions.value=await Promise.all(compareSelection.value.map(loadVersion));compareDialog.value=true}catch(e){ElMessage.error(e.message||'版本比较数据读取失败')}}
const snapshotRows=snapshot=>[
    ['成果名称',snapshot?.resultName],['复原类型',typeMap[snapshot?.restorationType]],['复原类别',categoryMap[snapshot?.restorationCategory]],
    ['目标部位',snapshot?.targetPart],['复原范围',snapshot?.restorationScope],['复原目的',snapshot?.restorationPurpose],
    ['依据摘要',snapshot?.basisSummary],['方法摘要',snapshot?.methodSummary],['结果摘要',snapshot?.resultSummary],
    ['不确定性',snapshot?.uncertaintySummary],['证据等级',snapshot?.evidenceLevel],['可信度',confidenceMap[snapshot?.confidenceLevel]],
    ['组成部分',(snapshot?.parts||[]).map(x=>`${x.partName}（${partMap[x.partType]?.[0]||x.partType}${x.modelObjectName?` / ${x.modelObjectName}`:''}）`).join('；')||'0 项'],
    ['三维标注',(snapshot?.parts||[]).filter(x=>x.annotationText||x.annotationPosition?.x!==undefined).map(x=>`${x.partName}：${x.annotationText||'坐标标注'}`).join('；')||'0 项'],
    ['依据来源',(snapshot?.sources||[]).map(x=>`${x.sourceTitle}（${x.evidenceLevel||'-'}）`).join('；')||'0 项'],
    ['方法参数',(snapshot?.methodParameters||[]).map(x=>`${x.name}=${x.value}${x.unit||''}`).join('；')||'0 项'],
    ['评价结论',snapshot?.evaluation?.finalConclusion],['后续监测',snapshot?.requiresMonitoring?`${snapshot?.monitoring?.indicators||'是'} · ${snapshot?.monitoring?.cycle||''}`:'否']
]
const restoreSnapshot=async version=>{try{await ElMessageBox.confirm(`恢复到 ${version.versionNo} 后，当前数据将由该历史快照替换；模型和媒体文件保持不变。`,'恢复历史版本',{type:'warning'});emit('restore-version',version.id);snapshotDialog.value=false;compareDialog.value=false}catch{}}
const switchTab=x=>tab.value=x
defineExpose({switchTab,newVersion})
watch(()=>props.result.id,()=>{tab.value='overview';selectedPartId.value=props.result.parts[0]?.id},{immediate:true})
</script>
<template><article class="paper" @input="dirty" @change="dirty">
<header><div><span>{{ result.resultCode }} · {{ typeMap[result.restorationType] }}</span><h2>{{ result.resultName }}</h2><p>{{ result.targetPart }} · {{ result.currentVersion }}</p></div><el-tag size="large">{{ result.resultStatus }}</el-tag></header>
<el-tabs v-model="tab">
<el-tab-pane label="成果概览" name="overview"><div class="hero"><img v-if="primary" :src="primary.fileUrl"><el-empty v-else description="暂无主成果图"/><aside><b>真实性说明</b><p>原始、修复、补配、证据复原、推测和不确定内容使用边框、文字和纹理区分。</p><strong>推测复原不等于原始遗存。</strong></aside></div>
<el-form label-position="top"><div class="grid"><el-form-item label="成果编号"><el-input v-model="result.resultCode" :disabled="readOnly"/></el-form-item><el-form-item label="成果名称"><el-input v-model="result.resultName" :disabled="readOnly"/></el-form-item><el-form-item label="复原类型"><el-select v-model="result.restorationType" :disabled="readOnly"><el-option v-for="(v,k) in typeMap" :key="k" :label="v" :value="k"/></el-select></el-form-item><el-form-item label="复原类别"><el-select v-model="result.restorationCategory" :disabled="readOnly"><el-option v-for="(v,k) in categoryMap" :key="k" :label="v" :value="k"/></el-select></el-form-item><el-form-item label="目标部位"><el-input v-model="result.targetPart" :disabled="readOnly"/></el-form-item><el-form-item label="负责人/参与人员"><el-input v-model="result.principal" :disabled="readOnly"/><el-input v-model="result.participantNames" class="mt" :disabled="readOnly"/></el-form-item><el-form-item class="wide" label="复原范围"><el-input v-model="result.restorationScope" type="textarea" :disabled="readOnly"/></el-form-item><el-form-item class="wide" label="复原目的"><el-input v-model="result.restorationPurpose" type="textarea" :disabled="readOnly"/></el-form-item><el-form-item class="wide" label="依据摘要"><el-input v-model="result.basisSummary" type="textarea" :rows="3" :disabled="readOnly"/></el-form-item><el-form-item class="wide" label="方法摘要"><el-input v-model="result.methodSummary" type="textarea" :rows="3" :disabled="readOnly"/></el-form-item><el-form-item class="wide" label="结果摘要"><el-input v-model="result.resultSummary" type="textarea" :rows="3" :disabled="readOnly"/></el-form-item><el-form-item class="wide" label="不确定性说明"><el-input v-model="result.uncertaintySummary" type="textarea" :rows="3" :disabled="readOnly"/></el-form-item></div></el-form>
<div class="links"><button @click="$emit('navigate','disease')">病害 {{ result.diseaseIds.length }}项</button><button @click="$emit('navigate','process',result.stepIds[0])">步骤 {{ result.stepIds.length }}项</button><button @click="$emit('navigate','comparison',result.comparisonIds[0])">对比 {{ result.comparisonIds.length }}组</button><button @click="$emit('navigate','detection')">检测 {{ result.detectionIds.length }}项</button></div></el-tab-pane>
<el-tab-pane label="组成部分" name="parts"><div class="legend"><span v-for="(v,k) in partMap" :key="k" :class="v[1]">{{ v[0] }}</span><b>推测复原 ≠ 原始遗存</b></div><div class="parts"><aside><el-button v-if="!readOnly" type="primary" :icon="Plus" @click="openPart()">新增组成部分</el-button><button v-for="x in result.parts" :key="x.id" :class="[partMap[x.partType][1],{active:selectedPart?.id===x.id}]" @click="selectedPartId=x.id"><b>{{ x.partName }}</b><small>{{ partMap[x.partType][0] }} · {{ x.percentageValue }}%</small></button></aside><main v-if="selectedPart"><div class="action"><h3>{{ selectedPart.partName }}</h3><div v-if="!readOnly"><el-button link :icon="Edit" @click="openPart(selectedPart)">编辑</el-button><el-button link type="danger" :icon="Delete" @click="removePart(selectedPart)">删除</el-button></div></div><dl><div><dt>位置</dt><dd>{{ selectedPart.targetLocation }}</dd></div><div><dt>范围</dt><dd>{{ selectedPart.scopeDescription }}</dd></div><div><dt>材料</dt><dd>{{ selectedPart.materialName||'无实体材料' }}</dd></div><div><dt>技术</dt><dd>{{ selectedPart.technique }}</dd></div><div><dt>证据/可信度</dt><dd>{{ selectedPart.evidenceLevel }} / {{ confidenceMap[selectedPart.confidenceLevel] }}</dd></div><div><dt>可拆除/可逆/可辨识</dt><dd>{{ selectedPart.removable?'是':'否' }} / {{ selectedPart.reversible?'是':'否' }} / {{ selectedPart.distinguishable?'是':'否' }}</dd></div><div><dt>标注</dt><dd>{{ selectedPart.annotationText }}</dd></div></dl><el-button @click="tab='sources';openSource()">关联依据</el-button><el-checkbox v-model="selectedPart.modelLayer" :disabled="readOnly">模型图层</el-checkbox></main></div></el-tab-pane>
<el-tab-pane label="复原依据" name="sources"><div class="action"><div><h3>复原依据来源</h3><p>只保存来源ID与必要摘要，不复制源数据。</p></div><el-button v-if="!readOnly" type="primary" :icon="Plus" @click="openSource()">新增/关联系统数据</el-button></div><article v-for="x in result.sources" :key="x.id" class="source"><b class="level">{{ x.evidenceLevel }}</b><div><h4>{{ x.sourceTitle }} <el-tag size="small">{{ sourceMap[x.sourceType] }}</el-tag></h4><p>{{ x.supportDescription }}</p><span>支持：{{ result.parts.find(p=>p.id===x.restorationPartId)?.partName||'整体成果' }} · {{ x.businessType }} #{{ x.businessId||'-' }}</span></div><div><el-button link :icon="View" @click="$emit('navigate',x.businessType,x.businessId)">查看来源</el-button><el-button v-if="!readOnly" link :icon="Edit" @click="openSource(x)">编辑</el-button><el-button v-if="!readOnly" link type="danger" @click="result.sources.splice(result.sources.indexOf(x),1);dirty()">解除</el-button></div></article></el-tab-pane>
<el-tab-pane label="成果资料" name="resources"><section><div class="action"><h3>成果影像</h3><el-button v-if="!readOnly" type="primary" @click="addMedia">上传成果影像</el-button><input ref="mediaInput" class="file-input" type="file" accept="image/*,video/*" @change="onMediaFile"></div><div class="media"><article v-for="x in result.media" :key="x.id"><img v-if="x.mediaType!=='video'" :src="x.thumbnailUrl||x.fileUrl"><div v-else class="file-placeholder">视频资料</div><b>{{ x.title }}</b><span>{{ stageMap[x.mediaStage] }} · {{ x.fileName }}</span><div><el-button v-if="!readOnly&&!x.isPrimary" link :icon="Star" @click="result.media.forEach(m=>m.isPrimary=m.id===x.id);dirty()">设主图</el-button><el-button v-if="!readOnly" link type="danger" @click="$emit('delete-media',x)">删除关联</el-button></div></article></div></section><section><div class="action"><div><h3>三维模型</h3><p>模型内容从 MySQL 读取并在浏览器中使用 WebGL 渲染。</p></div><el-button v-if="!readOnly" type="primary" @click="addModel">上传模型</el-button><input ref="modelInput" class="file-input" type="file" accept=".glb,.gltf,.obj,.fbx,.stl,.ply" @change="onModelFile"></div><div class="models"><article v-for="x in result.models" :key="x.id"><img v-if="x.previewImageUrl" :src="x.previewImageUrl"><div v-else class="model-placeholder">{{ x.fileFormat||'3D' }}</div><div><h4>{{ x.modelName }}</h4><p>{{ x.fileFormat }} · {{ x.polygonCount||0 }}面 · {{ x.textureCount||0 }}纹理 · {{ x.scaleUnit||'比例未填' }}</p><el-button type="primary" plain @click="viewModel(x)">WebGL 查看</el-button><el-button v-if="!readOnly" link type="danger" @click="$emit('delete-model',x)">删除模型</el-button></div></article></div><el-empty v-if="!result.models.length" description="尚未上传三维模型" :image-size="60"/></section><section><div class="action"><h3>方法与参数</h3><el-button v-if="!readOnly" type="primary" @click="addParameter">新增参数</el-button></div><el-table :data="result.methodParameters" border><el-table-column prop="name" label="参数"/><el-table-column prop="value" label="值"/><el-table-column prop="unit" label="单位"/><el-table-column prop="description" label="说明"/><el-table-column v-if="!readOnly" label="操作" width="70"><template #default="{row}"><el-button link type="danger" :icon="Delete" @click="result.methodParameters.splice(result.methodParameters.indexOf(row),1);dirty()"/></template></el-table-column></el-table></section></el-tab-pane>
<el-tab-pane label="版本与评价" name="version"><section><div class="action"><div><h3>历史版本与快照</h3><p>版本仅用于数据追踪和可视化比较，不包含审核、确认或推荐流程。</p></div><div><el-button :disabled="compareSelection.length!==2" @click="compareSelected">比较所选版本</el-button><el-button v-if="!readOnly" @click="newVersion(true)">复制当前数据</el-button><el-button v-if="!readOnly" type="primary" @click="newVersion(false)">记录新版本</el-button></div></div><el-table :data="result.versions" row-key="id" border @selection-change="onVersionSelection"><el-table-column type="selection" width="42"/><el-table-column prop="versionNo" label="版本" width="75"/><el-table-column prop="versionName" label="名称"/><el-table-column prop="changeDescription" label="修改说明"/><el-table-column prop="creator" label="记录人" width="90"/><el-table-column prop="createTime" label="记录时间" width="165"/><el-table-column label="状态" width="75"><template #default="{row}"><el-tag v-if="row.isCurrent">当前</el-tag><span v-else>历史</span></template></el-table-column><el-table-column label="操作" width="145" fixed="right"><template #default="{row}"><el-button link type="primary" @click="viewSnapshot(row)">查看快照</el-button><el-button v-if="!row.isCurrent&&!readOnly" link type="warning" @click="restoreSnapshot(row)">恢复</el-button></template></el-table-column></el-table></section><section><div class="action"><div><h3>成果评价</h3><p>综合得分只作数据可视化参考，不触发审核或确认流程。</p></div><b class="score">{{ score||'-' }}/5</b></div><div class="rates"><label v-for="x in [['evidenceScore','证据充分'],['structuralScore','结构合理'],['authenticityScore','历史真实'],['informationScore','信息保留'],['distinguishabilityScore','可辨识'],['reversibilityScore','可逆性'],['displayScore','展示效果'],['uncertaintyScore','不确定表达']]" :key="x[0]">{{ x[1] }}<el-rate v-model="result.evaluation[x[0]]" allow-half :disabled="readOnly" @change="dirty"/></label></div><el-form label-position="top"><div class="grid"><el-form-item label="证据评价"><el-input v-model="result.evaluation.evidenceComment" type="textarea" :disabled="readOnly"/></el-form-item><el-form-item label="结构评价"><el-input v-model="result.evaluation.structuralComment" type="textarea" :disabled="readOnly"/></el-form-item><el-form-item label="真实性评价"><el-input v-model="result.evaluation.authenticityComment" type="textarea" :disabled="readOnly"/></el-form-item><el-form-item label="可辨识性评价"><el-input v-model="result.evaluation.distinguishabilityComment" type="textarea" :disabled="readOnly"/></el-form-item><el-form-item label="不确定性评价"><el-input v-model="result.evaluation.uncertaintyComment" type="textarea" :disabled="readOnly"/></el-form-item><el-form-item label="学术评价"><el-input v-model="result.evaluation.academicComment" type="textarea" :disabled="readOnly"/></el-form-item><el-form-item class="wide" label="最终结论"><el-input v-model="result.evaluation.finalConclusion" type="textarea" :rows="4" :disabled="readOnly"/></el-form-item></div></el-form></section></el-tab-pane>
</el-tabs></article>
<el-dialog v-model="partDialog" title="组成部分" width="min(720px,95vw)"><el-form label-position="top"><div class="grid"><el-form-item label="名称"><el-input v-model="partForm.partName"/></el-form-item><el-form-item label="类型"><el-select v-model="partForm.partType"><el-option v-for="(v,k) in partMap" :key="k" :label="v[0]" :value="k"/></el-select></el-form-item><el-form-item label="位置"><el-input v-model="partForm.targetLocation"/></el-form-item><el-form-item label="比例参考"><el-input-number v-model="partForm.percentageValue" :min="0" :max="100"/></el-form-item><el-form-item class="wide" label="范围"><el-input v-model="partForm.scopeDescription" type="textarea"/></el-form-item><el-form-item label="材料"><el-input v-model="partForm.materialName"/></el-form-item><el-form-item label="技术"><el-input v-model="partForm.technique"/></el-form-item><el-form-item class="wide" label="三维标注与不确定性说明"><el-input v-model="partForm.annotationText" type="textarea"/></el-form-item><el-form-item class="wide"><el-checkbox v-model="partForm.removable">可拆除</el-checkbox><el-checkbox v-model="partForm.reversible">可逆</el-checkbox><el-checkbox v-model="partForm.distinguishable">可辨识</el-checkbox><el-checkbox v-model="partForm.modelLayer">作为模型图层</el-checkbox><el-checkbox v-if="partForm.modelLayer" v-model="partForm.layerVisible">默认显示图层</el-checkbox></el-form-item></div></el-form><template #footer><el-button @click="partDialog=false">取消</el-button><el-button type="primary" @click="savePart">保存</el-button></template></el-dialog>
<el-dialog v-model="sourceDialog" title="复原依据" width="min(680px,95vw)"><el-form label-position="top"><div class="grid"><el-form-item class="wide" label="依据名称"><el-input v-model="sourceForm.sourceTitle"/></el-form-item><el-form-item label="依据类型"><el-select v-model="sourceForm.sourceType"><el-option v-for="(v,k) in sourceMap" :key="k" :label="v" :value="k"/></el-select></el-form-item><el-form-item label="支持组成部分"><el-select v-model="sourceForm.restorationPartId"><el-option v-for="p in result.parts" :key="p.id" :label="p.partName" :value="p.id"/></el-select></el-form-item><el-form-item label="来源模块"><el-input v-model="sourceForm.businessType"/></el-form-item><el-form-item label="来源ID"><el-input-number v-model="sourceForm.businessId"/></el-form-item><el-form-item class="wide" label="支持内容"><el-input v-model="sourceForm.supportDescription" type="textarea" :rows="3"/></el-form-item></div></el-form><template #footer><el-button @click="sourceDialog=false">取消</el-button><el-button type="primary" @click="saveSource">保存</el-button></template></el-dialog>
<RestorationModelViewer v-model:visible="modelViewerVisible" :model="activeModel" :parts="result.parts" :read-only="readOnly" @dirty="dirty"/>
<el-dialog v-model="snapshotDialog" :title="`历史快照 · ${snapshotVersion?.versionNo||''}`" width="min(850px,95vw)"><el-descriptions v-if="snapshotVersion" :column="2" border><el-descriptions-item v-for="row in snapshotRows(snapshotVersion.snapshot)" :key="row[0]" :label="row[0]">{{ row[1]||'-' }}</el-descriptions-item></el-descriptions><template #footer><el-button @click="snapshotDialog=false">关闭</el-button><el-button v-if="snapshotVersion&&!snapshotVersion.isCurrent&&!readOnly" type="warning" @click="restoreSnapshot(snapshotVersion)">恢复此版本</el-button></template></el-dialog>
<el-dialog v-model="compareDialog" title="复原成果版本比较" width="min(1050px,96vw)"><el-table v-if="compareVersions.length===2" :data="snapshotRows(compareVersions[0].snapshot).map((row,index)=>({field:row[0],left:row[1],right:snapshotRows(compareVersions[1].snapshot)[index]?.[1]}))" border><el-table-column prop="field" label="比较字段" width="150"/><el-table-column :label="`${compareVersions[0].versionNo} · ${compareVersions[0].versionName}`" prop="left" min-width="260"/><el-table-column :label="`${compareVersions[1].versionNo} · ${compareVersions[1].versionName}`" prop="right" min-width="260"/><el-table-column label="变化" width="80"><template #default="{row}"><el-tag :type="String(row.left??'')===String(row.right??'')?'info':'warning'">{{ String(row.left??'')===String(row.right??'')?'相同':'有变化' }}</el-tag></template></el-table-column></el-table><template #footer><el-button @click="compareDialog=false">关闭</el-button></template></el-dialog>
</template>
